const p = $json;

// ============================================================
// 1. LIMPEZA DO REMETENTE (apenas para WhatsApp)
// ============================================================
let cliente = p.remetente || 'N/I';
if (p.canal?.toLowerCase() === 'whatsapp' && cliente.includes('@s.whatsapp.net')) {
  cliente = cliente.split('@')[0];
}
// Se for email ou outro, mantém o valor original (ex: "cliente@exemplo.com")

// ============================================================
// 2. FORMATAÇÃO DA DATA/HORA (fuso horário Angola UTC+1)
// ============================================================
function formatarDataAngola(dataISO) {
  const data = new Date(dataISO);
  // Adiciona 1 hora para UTC+1 (Angola)
  data.setHours(data.getHours() + 1);
  return data.toLocaleString('pt-AO', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false
  }).replace(',', '');
}

const timestampOriginal = p.timestamp || p.createdAt || new Date();
const dataHoraLocal = formatarDataAngola(timestampOriginal);

// ============================================================
// 3. CONFIGURAÇÃO DE EMOJIS E CABEÇALHO
// ============================================================
const e_prio  = p.prioridade_label === 'ALTA' ? '🔴' : p.prioridade_label === 'MÉDIA' ? '🟡' : '🟢';
const e_canal = (p.canal || '').toLowerCase() === 'whatsapp' ? '📱 WhatsApp' : '📧 Email';
const e_tipo  = p.tipo_pedido === 'proforma' ? '📋 PROFORMA' : (p.categoria === 'compra' ? '📦 PEDIDO DE COMPRA' : 'ℹ️ OUTRO CONTACTO');

// ============================================================
// 4. CONSTRUÇÃO DA MENSAGEM
// ============================================================
let msg = `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
msg += `${e_prio} ${e_tipo}\n`;
msg += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;

msg += `${e_canal}  |  👤 Cliente: ${cliente}\n`;
msg += `🕐 Data/Hora: ${dataHoraLocal}\n\n`;

// Prioridade e SLA
if (p.prioridade_label) {
  msg += `${e_prio} Prioridade: ${p.prioridade_label}  |  ⏱️ SLA: ${p.sla_minutos || 60} min\n`;
}
if (p.margem_percentual > 0) {
  msg += `💰 Margem: ${p.margem_percentual}%\n`;
}
msg += `\n`;

// Resumo da IA (se existir)
if (p.resumo_classificacao) {
  msg += `📌 RESUMO DA INTERAÇÃO:\n${p.resumo_classificacao}\n\n`;
}

// Itens (apenas para compra)
if (p.categoria === 'compra' && p.itens && p.itens.length > 0) {
  msg += `📦 ITENS (${p.itens.length}):\n`;
  p.itens.forEach((it, i) => {
    const codigo = it.codigo ? `[${it.codigo}] ` : '';
    const unidade = it.unidade ? ` (${it.unidade})` : '';
    msg += `   ${i+1}. ${codigo}${it.descricao}${unidade} × ${it.quantidade}\n`;
  });
  msg += `\n`;
}

// Mensagem/Documento completo (prioriza texto_enriquecido)
const textoCompleto = p.texto_enriquecido || p.texto || '';
if (textoCompleto && p.categoria !== 'compra') {
  msg += `📝 MENSAGEM COMPLETA:\n`;
  msg += `${textoCompleto}\n\n`;
}

// Fontes de dados processadas
if (p.tipos_anexos || p.fontes_dados) {
  let fontes = [];
  try {
    const f = p.tipos_anexos || (typeof p.fontes_dados === 'string' ? JSON.parse(p.fontes_dados) : p.fontes_dados);
    if (f.tem_pdf || f.pdf) fontes.push('📄 PDF');
    if (f.tem_imagem || f.ocr) fontes.push('📷 Imagem/OCR');
    if (f.tem_excel || f.excel) fontes.push('📊 Excel');
    if (f.tem_audio || f.audio) fontes.push('🎙 Áudio');
  } catch(e) {}
  if (fontes.length) {
    msg += `🔍 FONTES PROCESSADAS: ${fontes.join(', ')}\n\n`;
  }
}

// Rodapé
msg += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
msg += `🆔 ID: ${p.pedido_id || 'N/A'}\n`;
msg += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`;

// ============================================================
// 5. SAÍDA
// ============================================================
return { 
  json: { 
    ...p, 
    mensagem_equipa: msg, 
    hora_entrada: new Date().toISOString(),
    cliente_limpo: cliente   // agora com e-mail intacto quando aplicável
  } 
};

const p = $json;
const query = `INSERT INTO pedidos (id,tipo,cliente_id,canal,itens_json,total_itens,prioridade,margem,timestamp,status) VALUES (@id,@tipo,@cliente,@canal,@itens,@total,@prioridade,@margem,@timestamp,@status)`;
const params = [
  {name:'id',value:p.pedido_id,type:'string'},{name:'tipo',value:p.categoria||p.tipo_pedido,type:'string'},
  {name:'cliente',value:p.remetente,type:'string'},{name:'canal',value:p.canal,type:'string'},
  {name:'itens',value:JSON.stringify(p.itens||[]),type:'string'},{name:'total',value:p.total_itens||0,type:'number'},
  {name:'prioridade',value:p.prioridade||3,type:'number'},{name:'margem',value:p.margem_percentual||0,type:'number'},
  {name:'timestamp',value:new Date().toISOString(),type:'string'},{name:'status',value:'recebido',type:'string'}
];
return { json: {...p,query,params} };

// 1. Puxa todos os dados que o WF2 enviou para o WF3
const dadosOriginais = $('When Executed by Another Workflow').first().json;

// 2. Pega na mensagem gerada
const texto = $json.output || $json.text || $json.content || 'A sua mensagem foi recebida. A nossa equipa entrará em contacto brevemente.';

// 3. Junta tudo para o nó do WhatsApp saber para onde enviar
return { 
  json: { 
    ...dadosOriginais, 
    texto_resposta: texto 
  } 
};
